import { Router } from "express";
import { listProducts, getProduct, adjustStock } from "../services/productService.js";

const router = Router();

// GET /products - list all products, optionally filter by category / price range
router.get("/products", (req, res) => {
  const { category, minPrice, maxPrice } = req.query;

  const minParsed = typeof minPrice === "string" ? parseFloat(minPrice) : NaN;
  const maxParsed = typeof maxPrice === "string" ? parseFloat(maxPrice) : NaN;

  res.json(
    listProducts({
      category: typeof category === "string" ? category : undefined,
      minPrice: !isNaN(minParsed) ? minParsed : undefined,
      maxPrice: !isNaN(maxParsed) ? maxParsed : undefined,
    })
  );
});

// GET /products/:id
router.get("/products/:id", (req, res) => {
  const result = getProduct(parseInt(req.params.id, 10));
  if (!result.ok) {
    res.status(result.status).json({ error: result.error });
    return;
  }
  res.json(result.data);
});

// PATCH /products/:id/stock - update stock
router.patch("/products/:id/stock", (req, res) => {
  const { adjustment } = req.body as { adjustment: unknown };
  if (typeof adjustment !== "number") {
    res.status(400).json({ error: "adjustment must be a number" });
    return;
  }

  const result = adjustStock(parseInt(req.params.id, 10), adjustment);
  if (!result.ok) {
    res.status(result.status).json({ error: result.error });
    return;
  }
  res.json(result.data);
});

export { router as productRouter };

